const out = [];
const seen = new Set();
const inputItems = $input.all();

const stripFences = (raw) => {
  let txt = String(raw || '').replace(/^\uFEFF/, '').trim();
  if (txt.startsWith('```json')) txt = txt.slice(7);
  else if (txt.startsWith('```')) txt = txt.slice(3);
  if (txt.endsWith('```')) txt = txt.slice(0, -3);
  return txt.trim();
};

const extractRaw = (llm) => {
  if (typeof llm?.text === 'string') return llm.text;
  if (typeof llm?.output === 'string') return llm.output;
  if (typeof llm?.answer === 'string') return llm.answer;
  if (typeof llm?.result === 'string') return llm.result;
  if (typeof llm?.response?.text === 'string') return llm.response.text;
  if (typeof llm?.response === 'string') return llm.response;

  const contents = [llm?.response?.content, llm?.content, llm?.output?.content];
  for (const content of contents) {
    if (Array.isArray(content)) {
      const joined = content
        .map((c) => {
          if (typeof c === 'string') return c;
          if (typeof c?.text === 'string') return c.text;
          if (typeof c?.content === 'string') return c.content;
          return '';
        })
        .filter(Boolean)
        .join('\n');
      if (joined) return joined;
    }
  }

  const choice = llm?.choices?.[0]?.message?.content;
  if (typeof choice === 'string') return choice;

  return '';
};

const parseMaybeJson = (raw) => {
  if (!raw || typeof raw !== 'string') return null;
  const txt = stripFences(raw);
  if (!txt) return null;

  try { return JSON.parse(txt); } catch (_e) {}

  // Try largest JSON object range
  const firstObj = txt.indexOf('{');
  const lastObj = txt.lastIndexOf('}');
  if (firstObj >= 0 && lastObj > firstObj) {
    try { return JSON.parse(txt.slice(firstObj, lastObj + 1)); } catch (_e) {}
  }

  // Try largest JSON array range
  const firstArr = txt.indexOf('[');
  const lastArr = txt.lastIndexOf(']');
  if (firstArr >= 0 && lastArr > firstArr) {
    try { return JSON.parse(txt.slice(firstArr, lastArr + 1)); } catch (_e) {}
  }

  return null;
};

const keywordRe = /\b(import|export|const|let|var|function|class|interface|type|async|await|if|return|try|catch|throw)\b/;
const narrativeRe = /^(deve|validar|implementar|criar|adicionar|ajustar|mudar|alterar)\b/i;
const fileHeaderRe = /^\s*\/\/\s*file:\s*.+\.(ts|tsx|js|jsx|mjs|cjs)\b/im;

const inferFilePath = (repoName, changeId) => {
  const repo = String(repoName || '').toLowerCase();
  const id = Number(changeId);
  const suffix = Number.isFinite(id) ? String(id) : 'x';
  if (repo.includes('domain')) return `src/domain/generated-change-${suffix}.ts`;
  if (repo.includes('api')) return `src/modules/generated-change-${suffix}.ts`;
  if (repo.includes('mobile')) return `src/features/generated-change-${suffix}.ts`;
  return `src/generated-change-${suffix}.ts`;
};

const ensureFileHeader = (text, repoName, changeId) => {
  if (fileHeaderRe.test(text)) return text;
  return `// file: ${inferFilePath(repoName, changeId)}\n${text}`;
};

const isLikelyCode = (value) => {
  const text = stripFences(value);
  if (!text || text.length < 20) return false;
  const hasKeyword = keywordRe.test(text);
  const hasSyntax = /[{}();=>]/.test(text) || /\n\s{2,}/.test(text);
  const narrativeOnly = narrativeRe.test(text) && !hasSyntax;
  return hasKeyword && hasSyntax && !narrativeOnly;
};

const pushRow = (items, changeId, code, repoName) => {
  const id = Number(changeId);
  const base = stripFences(code);
  if (!Number.isFinite(id) || !base) return;
  if (!isLikelyCode(base)) return;

  const text = ensureFileHeader(base, repoName, id);
  const key = id + '::' + text;
  if (seen.has(key)) return;
  seen.add(key);
  items.push({ change_id: id, code: text });
};

const collectRowCandidates = (row) => {
  if (!row || typeof row !== 'object') return [];
  const candidates = [];

  for (const k of ['code', 'snippet', 'source', 'source_code', 'desc', 'description', 'text', 'content']) {
    if (typeof row[k] === 'string' && row[k].trim()) candidates.push(row[k]);
  }

  for (const k of ['code_changes', 'codes', 'snippets']) {
    if (Array.isArray(row[k])) {
      for (const item of row[k]) {
        if (typeof item === 'string' && item.trim()) candidates.push(item);
        else if (item && typeof item === 'object') {
          if (typeof item.code === 'string' && item.code.trim()) candidates.push(item.code);
          if (typeof item.source === 'string' && item.source.trim()) candidates.push(item.source);
          if (typeof item.snippet === 'string' && item.snippet.trim()) candidates.push(item.snippet);
          if (typeof item.content === 'string' && item.content.trim()) candidates.push(item.content);
        }
      }
    }
  }

  return candidates;
};

const extractCodeBlocksFromRaw = (raw) => {
  const txt = String(raw || '');
  const blocks = [];
  const re = /```(?:ts|tsx|js|jsx|typescript|javascript)?\s*([\s\S]*?)```/gi;
  let m;
  while ((m = re.exec(txt)) !== null) {
    const block = String(m[1] || '').trim();
    if (block) blocks.push(block);
  }

  if (blocks.length === 0) {
    // If no fenced blocks, try splitting by file headers
    const parts = txt.split(/(?=^\s*\/\/\s*file:\s*.+$)/gim).map((p) => p.trim()).filter(Boolean);
    for (const p of parts) blocks.push(p);
  }

  return blocks;
};

const rowsFromPayload = (payload, raw, fallbackChangeId, repoName, suggestedCodes) => {
  const items = [];
  const cid = Number(fallbackChangeId);

  if (Array.isArray(payload)) {
    for (const row of payload) {
      const rowId = Number(row?.change_id ?? cid);
      const candidates = collectRowCandidates(row);
      for (const code of candidates) pushRow(items, rowId, code, repoName);
    }
  } else if (payload && typeof payload === 'object') {
    if (Array.isArray(payload.rows)) {
      for (const row of payload.rows) {
        const rowId = Number(row?.change_id ?? cid);
        const candidates = collectRowCandidates(row);
        for (const code of candidates) pushRow(items, rowId, code, repoName);
      }
    }

    const topCandidates = collectRowCandidates(payload);
    for (const code of topCandidates) pushRow(items, cid, code, repoName);
  }

  if (items.length === 0) {
    const rawBlocks = extractCodeBlocksFromRaw(raw);
    for (const code of rawBlocks) pushRow(items, cid, code, repoName);
  }

  if (items.length === 0 && Array.isArray(suggestedCodes)) {
    for (const code of suggestedCodes) pushRow(items, cid, code, repoName);
  }

  return items;
};

for (let i = 0; i < inputItems.length; i++) {
  const llm = inputItems[i].json || {};
  let src = {};
  try { src = $item(i).$node['Build Code Change Rows'].json || {}; } catch (_e) { src = {}; }

  const raw = extractRaw(llm);
  const parsed = parseMaybeJson(raw);
  const rows = rowsFromPayload(
    parsed,
    raw,
    src.change_id ?? llm.change_id,
    src.repo_name ?? llm.repo_name,
    src.suggested_code_changes || []
  );

  for (const row of rows) out.push({ json: row });
}

return out;
